export async function seedWorkflowDefinitions(payload: Payload): Promise<void> {
  const name = 'erpax-universal'
  const data = {
    name,
    description: 'The one universal erpax process graph the standards collectively define — 7 domains merged, harmony gaps closed.',
    version: 1,
    targetCollection: 'quotes',
    triggerEvent: 'beforeStatusChange' as const,
    steps: [{ order: 1, name: 'Universal lifecycle gate', kind: 'service_task' as const, serviceHandler: 'erpax-universal' }],
    stateMachine: UNIFIED_STATE_MACHINE,
    isActive: true,
  }
  const existing = await payload.find({ collection: 'workflow-definitions', where: { name: { equals: name } }, limit: 1, overrideAccess: true })
  if (existing.docs.length > 0) {
    await payload.update({ collection: 'workflow-definitions', id: existing.docs[0].id, data: data as Partial<WorkflowDefinition>, overrideAccess: true })
  } else {
    await payload.create({ collection: 'workflow-definitions', data: data as unknown as WorkflowDefinition, overrideAccess: true })
  }
}
